package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreHeaderCase_DefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);
        assertTrue(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_ExcelFormat() {
        CSVFormat format = CSVFormat.EXCEL;
        // EXCEL inherits from DEFAULT and calls withIgnoreEmptyLines and withAllowMissingColumnNames,
        // but does not set ignoreHeaderCase explicitly, so default false expected
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_CustomFormat() {
        CSVFormat format = CSVFormat.newFormat(';')
                .withIgnoreHeaderCase(true);
        assertTrue(format.getIgnoreHeaderCase());
    }
}
